/**
 * Builds the WebView editor bundle (Joplin-style: pre-bundled, no CDN).
 * Run: node scripts/buildEditorBundle.js
 * Output: assets/editor/editorBundle.generated.ts
 */
const fs = require("fs");
const path = require("path");

async function build() {
  const esbuild = require("esbuild");
  const entry = path.join(__dirname, "../assets/editor/editorEntry.ts");
  const outFile = path.join(__dirname, "../assets/editor/editorBundle.out.js");
  const generatedPath = path.join(__dirname, "../assets/editor/editorBundle.generated.ts");

  await esbuild.build({
    entryPoints: [entry],
    bundle: true,
    format: "iife",
    platform: "browser",
    target: "es2020",
    outfile: outFile,
    minify: true,
    sourcemap: false,
    define: {
      "process.env.NODE_ENV": '"production"',
    },
  });

  const bundleContent = fs.readFileSync(outFile, "utf8");
  fs.unlinkSync(outFile);

  const escaped = JSON.stringify(bundleContent);
  const generated = `// Generated by scripts/buildEditorBundle.js — do not edit.
export const EDITOR_BUNDLE: string = ${escaped};
`;

  fs.writeFileSync(generatedPath, generated, "utf8");
  console.log("Editor bundle written to assets/editor/editorBundle.generated.ts");
}

build().catch((err) => {
  console.error(err);
  process.exit(1);
});
